# ---- table region removal + embed ----
TABLE_BOX=(432,208,896,380)  # x0,y0,x1,y1 ; keeps the sentence above and the "...and what if" line below
def elem_bbox(s):
    if '<path' in s:
        d=t.attr(s,'d');  return t.bbox(d) if d else None
    if '<rect' in s:
        w=t.attr(s,'width'); h=t.attr(s,'height')
        if not(w and h): return None
        m=re.search(r'translate\(([-\d.]+)[ ,]+([-\d.]+)\)',s)
        ox,oy=(float(m.group(1)),float(m.group(2))) if m else (float(t.attr(s,'x') or 0),float(t.attr(s,'y') or 0))
        return (ox,oy,ox+float(w),oy+float(h))
    return None
def in_table(s):
    bb=elem_bbox(s)
    if not bb: return False
    cx=(bb[0]+bb[2])/2; cy=(bb[1]+bb[3])/2
    return TABLE_BOX[0]<=cx<=TABLE_BOX[2] and TABLE_BOX[1]<=cy<=TABLE_BOX[3]

def table_block():
    bx0,by0,bx1,by1=TABLE_BOX
    white=f'<rect x="{bx0}" y="{by0}" width="{bx1-bx0}" height="{by1-by0}" fill="white"/>'
    if TABLE_MODE=="none":
        return white
    raw=open(ASSET).read()
    raw=re.sub(r'<\?xml[^>]*\?>','',raw); raw=re.sub(r'<!DOCTYPE[^>]*>','',raw,flags=re.S)
    m=re.search(r'<svg\b[^>]*>',raw); inner=raw[m.end():]
    inner=re.sub(r'</svg>\s*$','',inner)  # strip outer svg tags -> inner content
    # height-fit into the box (asset 628.2 x 240.90705); group transform renders like standalone
    s=171.0/240.90705
    # fill="#1A1A1A": asset text glyphs carry no fill of their own and would otherwise
    # inherit the poster root's fill="none" (invisible). Row rects keep their explicit fills.
    g=(f'<g transform="translate({bx0},209) scale({s:.5f})" fill="#1A1A1A">{inner}</g>')
    return white+"\n"+g

